@@ -0,0 +1,396 @@
+import { describe, it, expect, beforeEach } from 'vitest';
+import { EmailAdapter } from '../../src/adapters/email.adapter.js';
+import type { NotificationPayload } from '../../src/models/notification.js';
+
+describe('EmailAdapter', () => {
+  let adapter: EmailAdapter;
+
+  beforeEach(() => {
+    adapter = new EmailAdapter();
+  });
+
+  // ---------------------------------------------------------------------------
+  // Basic send
+  // ---------------------------------------------------------------------------
+
+  describe('send', () => {
+    it('should successfully send a valid email', async () => {
+      const payload: NotificationPayload = {
+        type: 'order_confirmation',
+        recipient: 'alice@example.com',
+        subject: 'Order Confirmation: order-1',
+        body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
+        metadata: { orderId: 'order-1', userId: 'user-1' },
+      };
+
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(true);
+      expect(result.channel).toBe('email');
+      expect(result.error).toBeUndefined();
+    });
+
+    it('should store sent email with correct fields', async () => {
+      const payload: NotificationPayload = {
+        type: 'order_confirmation',
+        recipient: 'bob@example.com',
+        subject: 'Order Confirmation: order-2',
+        body: 'Your order has been placed.',
+        metadata: { orderId: 'order-2' },
+      };
+
+      await adapter.send(payload);
+
+      const emails = adapter.getSentEmails();
+      expect(emails).toHaveLength(1);
+      expect(emails[0]?.to).toBe('bob@example.com');
+      expect(emails[0]?.from).toBe('noreply@taskflowpro.com');
+      expect(emails[0]?.subject).toContain('Order Confirmation');
+      expect(emails[0]?.body).toContain('Your order has been placed.');
+      expect(emails[0]?.html).toContain('<h2>Order Confirmation</h2>');
+      expect(emails[0]?.sentAt).toBeInstanceOf(Date);
+      expect(emails[0]?.attempts).toBe(1);
+    });
+
+    it('should report channel as email', () => {
+      expect(adapter.channel).toBe('email');
+    });
+  });
+
+  // ---------------------------------------------------------------------------
+  // Recipient validation
+  // ---------------------------------------------------------------------------
+
+  describe('recipient validation', () => {
+    it('should reject empty recipient', async () => {
+      const payload: NotificationPayload = {
+        type: 'welcome',
+        recipient: '',
+        subject: 'Welcome',
+        body: 'Hello!',
+      };
+
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('required');
+      expect(adapter.getSentEmails()).toHaveLength(0);
+    });
+
+    it('should reject invalid email format', async () => {
+      const payload: NotificationPayload = {
+        type: 'welcome',
+        recipient: 'not-an-email',
+        subject: 'Welcome',
+        body: 'Hello!',
+      };
+
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Invalid email format');
+      expect(adapter.getSentEmails()).toHaveLength(0);
+    });
+
+    it('should accept valid email addresses', async () => {
+      const validEmails = [
+        'user@example.com',
+        'user.name@example.co.uk',
+        'user+tag@example.com',
+      ];
+
+      for (const email of validEmails) {
+        const a = new EmailAdapter();
+        const result = await a.send({
+          type: 'welcome',
+          recipient: email,
+          subject: 'Test',
+          body: 'Hello',
+        });
+        expect(result.success).toBe(true);
+      }
+    });
+  });
+
+  // ---------------------------------------------------------------------------
+  // Template rendering
+  // ---------------------------------------------------------------------------
+
+  describe('template rendering', () => {
+    it('should render order_confirmation template with order details', async () => {
+      await adapter.send({
+        type: 'order_confirmation',
+        recipient: 'user@example.com',
+        subject: 'Order Confirmation: order-42',
+        body: 'Items: Widget x3. Total: $30.00',
+        metadata: { orderId: 'order-42', userId: 'user-1' },
+      });
+
+      const email = adapter.getSentEmails()[0]!;
+      expect(email.subject).toContain('TaskFlow Pro');
+      expect(email.subject).toContain('order-42');
+      expect(email.body).toContain('Thank you for your order');
+      expect(email.body).toContain('Order ID: order-42');
+      expect(email.html).toContain('<h2>Order Confirmation</h2>');
+      expect(email.html).toContain('order-42');
+    });
+
+    it('should render order_status_update template', async () => {
+      await adapter.send({
+        type: 'order_status_update',
+        recipient: 'user@example.com',
+        subject: 'Order Update: order-5',
+        body: 'Your order status has changed from pending to confirmed.',
+        metadata: { orderId: 'order-5', previousStatus: 'pending', newStatus: 'confirmed' },
+      });
+
+      const email = adapter.getSentEmails()[0]!;
+      expect(email.subject).toContain('Order Update');
+      expect(email.subject).toContain('order-5');
+      expect(email.body).toContain('New Status: confirmed');
+      expect(email.html).toContain('Order Status Update');
+    });
+
+    it('should render welcome template', async () => {
+      await adapter.send({
+        type: 'welcome',
+        recipient: 'newuser@example.com',
+        subject: 'Welcome',
+        body: 'Thanks for joining!',
+      });
+
+      const email = adapter.getSentEmails()[0]!;
+      expect(email.subject).toContain('Welcome to TaskFlow Pro');
+      expect(email.body).toContain('Welcome to TaskFlow Pro');
+      expect(email.body).toContain('Thanks for joining!');
+      expect(email.html).toContain('Welcome to TaskFlow Pro');
+    });
+
+    it('should render account_updated template', async () => {
+      await adapter.send({
+        type: 'account_updated',
+        recipient: 'user@example.com',
+        subject: 'Account Updated',
+        body: 'Your email has been changed.',
+      });
+
+      const email = adapter.getSentEmails()[0]!;
+      expect(email.subject).toContain('Account Updated');
+      expect(email.body).toContain('contact support');
+      expect(email.html).toContain('Account Updated');
+    });
+
+    it('should produce valid HTML with doctype', async () => {
+      await adapter.send({
+        type: 'welcome',
+        recipient: 'user@example.com',
+        subject: 'Test',
+        body: 'Hello',
+      });
+
+      const email = adapter.getSentEmails()[0]!;
+      expect(email.html).toMatch(/^<!DOCTYPE html>/);
+      expect(email.html).toContain('</html>');
+    });
+
+    it('should escape HTML entities in user content', async () => {
+      await adapter.send({
+        type: 'welcome',
+        recipient: 'user@example.com',
+        subject: 'Test',
+        body: 'Hello <script>alert("xss")</script> & "quotes"',
+      });
+
+      const email = adapter.getSentEmails()[0]!;
+      expect(email.html).not.toContain('<script>');
+      expect(email.html).toContain('&lt;script&gt;');
+      expect(email.html).toContain('&amp;');
+    });
+  });
+
+  // ---------------------------------------------------------------------------
+  // Configuration
+  // ---------------------------------------------------------------------------
+
+  describe('configuration', () => {
+    it('should use default config when none provided', () => {
+      const config = adapter.getConfig();
+      expect(config.fromAddress).toBe('noreply@taskflowpro.com');
+      expect(config.appName).toBe('TaskFlow Pro');
+      expect(config.maxRetries).toBe(2);
+    });
+
+    it('should accept custom config overrides', () => {
+      const custom = new EmailAdapter({
+        fromAddress: 'support@myapp.com',
+        appName: 'MyApp',
+        maxRetries: 5,
+      });
+
+      const config = custom.getConfig();
+      expect(config.fromAddress).toBe('support@myapp.com');
+      expect(config.appName).toBe('MyApp');
+      expect(config.maxRetries).toBe(5);
+    });
+
+    it('should use custom appName in templates', async () => {
+      const custom = new EmailAdapter({ appName: 'CustomApp' });
+      await custom.send({
+        type: 'welcome',
+        recipient: 'user@example.com',
+        subject: 'Welcome',
+        body: 'Hi',
+      });
+
+      const email = custom.getSentEmails()[0]!;
+      expect(email.subject).toContain('CustomApp');
+      expect(email.body).toContain('CustomApp');
+    });
+
+    it('should use custom fromAddress', async () => {
+      const custom = new EmailAdapter({ fromAddress: 'hello@custom.com' });
+      await custom.send({
+        type: 'welcome',
+        recipient: 'user@example.com',
+        subject: 'Test',
+        body: 'Hello',
+      });
+
+      expect(custom.getSentEmails()[0]?.from).toBe('hello@custom.com');
+    });
+  });
+
+  // ---------------------------------------------------------------------------
+  // Retry logic
+  // ---------------------------------------------------------------------------
+
+  describe('retry logic', () => {
+    it('should retry on transport failure', async () => {
+      let callCount = 0;
+      adapter.setTransport(async () => {
+        callCount++;
+        if (callCount < 3) {
+          throw new Error('Connection timeout');
+        }
+        return true;
+      });
+
+      const result = await adapter.send({
+        type: 'welcome',
+        recipient: 'user@example.com',
+        subject: 'Test',
+        body: 'Hello',
+      });
+
+      expect(result.success).toBe(true);
+      expect(callCount).toBe(3);
+      expect(adapter.getSentEmails()[0]?.attempts).toBe(3);
+    });
+
+    it('should fail after all retries exhausted', async () => {
+      adapter.setTransport(async () => {
+        throw new Error('Permanent failure');
+      });
+
+      const result = await adapter.send({
+        type: 'welcome',
+        recipient: 'user@example.com',
+        subject: 'Test',
+        body: 'Hello',
+      });
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Permanent failure');
+      expect(adapter.getSentEmails()).toHaveLength(0);
+    });
+
+    it('should fail when transport returns false', async () => {
+      adapter.setTransport(async () => false);
+
+      const result = await adapter.send({
+        type: 'welcome',
+        recipient: 'user@example.com',
+        subject: 'Test',
+        body: 'Hello',
+      });
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Transport returned failure');
+    });
+
+    it('should respect maxRetries config', async () => {
+      const noRetry = new EmailAdapter({ maxRetries: 0 });
+      let callCount = 0;
+      noRetry.setTransport(async () => {
+        callCount++;
+        throw new Error('fail');
+      });
+
+      await noRetry.send({
+        type: 'welcome',
+        recipient: 'user@example.com',
+        subject: 'Test',
+        body: 'Hello',
+      });
+
+      expect(callCount).toBe(1);
+    });
+  });
+
+  // ---------------------------------------------------------------------------
+  // Inspection helpers
+  // ---------------------------------------------------------------------------
+
+  describe('inspection helpers', () => {
+    it('should clear sent emails', async () => {
+      await adapter.send({
+        type: 'welcome',
+        recipient: 'user@example.com',
+        subject: 'Test',
+        body: 'Hello',
+      });
+
+      expect(adapter.getSentEmails()).toHaveLength(1);
+      adapter.clearSentEmails();
+      expect(adapter.getSentEmails()).toHaveLength(0);
+    });
