/**
 * Email notification adapter — delivers notifications via email.
 *
 * Implements the NotificationAdapter interface with:
 * - Template rendering per notification type
 * - Recipient resolution (validates email format)
 * - Configurable email settings (from address, retry, etc.)
 * - Delivery tracking with sent email log
 *
 * In production, swap the transport layer (the internal `sendEmail` method)
 * for a real provider (SendGrid, SES, SMTP). The adapter contract stays the same.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/** Configuration for the email adapter. */
export interface EmailAdapterConfig {
  /** Sender address shown in the "From" field. */
  fromAddress: string;
  /** Application name used in templates. */
  appName: string;
  /** Number of retry attempts on transient failures. */
  maxRetries: number;
}

const DEFAULT_CONFIG: EmailAdapterConfig = {
  fromAddress: 'noreply@taskflowpro.com',
  appName: 'TaskFlow Pro',
  maxRetries: 2,
};

/** Record of a rendered and sent email. */
export interface SentEmail {
  to: string;
  from: string;
  subject: string;
  body: string;
  html: string;
  sentAt: Date;
  attempts: number;
}

/** Simple email-format check. */
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private config: EmailAdapterConfig;
  private sentEmails: SentEmail[] = [];
  /** Optional hook to simulate transport failures in tests. */
  private transportFn: ((email: SentEmail) => Promise<boolean>) | null = null;

  constructor(config?: Partial<EmailAdapterConfig>) {
    this.config = { ...DEFAULT_CONFIG, ...config };
  }

  // ---------------------------------------------------------------------------
  // NotificationAdapter interface
  // ---------------------------------------------------------------------------

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    // 1. Resolve / validate recipient
    const recipientError = this.validateRecipient(payload.recipient);
    if (recipientError) {
      this.logger.error(`Invalid recipient "${payload.recipient}": ${recipientError}`);
      return { success: false, channel: this.channel, error: recipientError };
    }

    // 2. Render email content from template
    const { subject, textBody, htmlBody } = this.renderTemplate(payload);

    // 3. Attempt delivery (with retries)
    const email: SentEmail = {
      to: payload.recipient,
      from: this.config.fromAddress,
      subject,
      body: textBody,
      html: htmlBody,
      sentAt: new Date(),
      attempts: 0,
    };

    const maxAttempts = this.config.maxRetries + 1;
    let lastError: string | undefined;

    for (let attempt = 1; attempt <= maxAttempts; attempt++) {
      email.attempts = attempt;
      try {
        const ok = await this.sendEmail(email);
        if (ok) {
          this.sentEmails.push(email);
          this.logger.info(`Email sent to ${payload.recipient}: "${subject}" (attempt ${attempt})`);
          return { success: true, channel: this.channel };
        }
        lastError = 'Transport returned failure';
      } catch (err) {
        lastError = err instanceof Error ? err.message : String(err);
        this.logger.warn(
          `Email delivery attempt ${attempt}/${maxAttempts} failed for ${payload.recipient}: ${lastError}`,
        );
      }
    }

    // All retries exhausted
    this.logger.error(`Email delivery failed for ${payload.recipient} after ${maxAttempts} attempts: ${lastError}`);
    return { success: false, channel: this.channel, error: lastError };
  }

  // ---------------------------------------------------------------------------
  // Template rendering
  // ---------------------------------------------------------------------------

  /**
   * Render the notification payload into email subject, plain-text body, and
   * HTML body, choosing a template based on the notification type.
   */
  private renderTemplate(payload: NotificationPayload): {
    subject: string;
    textBody: string;
    htmlBody: string;
  } {
    switch (payload.type) {
      case 'order_confirmation':
        return this.renderOrderConfirmation(payload);
      case 'order_status_update':
        return this.renderOrderStatusUpdate(payload);
      case 'welcome':
        return this.renderWelcome(payload);
      case 'account_updated':
        return this.renderAccountUpdated(payload);
      default:
        return this.renderGeneric(payload);
    }
  }

  private renderOrderConfirmation(payload: NotificationPayload): {
    subject: string;
    textBody: string;
    htmlBody: string;
  } {
    const orderId = (payload.metadata?.orderId as string) ?? 'N/A';
    const subject = `${this.config.appName} — Order Confirmation: ${orderId}`;
    const textBody = [
      `Hi,`,
      ``,
      `Thank you for your order!`,
      ``,
      payload.body,
      ``,
      `Order ID: ${orderId}`,
      ``,
      `If you have questions, reply to this email.`,
      ``,
      `— The ${this.config.appName} Team`,
    ].join('\n');

    const htmlBody = this.wrapHtml(
      `<h2>Order Confirmation</h2>` +
        `<p>Thank you for your order!</p>` +
        `<p>${this.escapeHtml(payload.body)}</p>` +
        `<p><strong>Order ID:</strong> ${this.escapeHtml(orderId)}</p>` +
        `<p>If you have questions, reply to this email.</p>`,
    );

    return { subject, textBody, htmlBody };
  }

  private renderOrderStatusUpdate(payload: NotificationPayload): {
    subject: string;
    textBody: string;
    htmlBody: string;
  } {
    const orderId = (payload.metadata?.orderId as string) ?? 'N/A';
    const newStatus = (payload.metadata?.newStatus as string) ?? '';
    const subject = `${this.config.appName} — Order Update: ${orderId}`;
    const textBody = [
      `Hi,`,
      ``,
      payload.body,
      ``,
      `Order ID: ${orderId}`,
      `New Status: ${newStatus}`,
      ``,
      `— The ${this.config.appName} Team`,
    ].join('\n');

    const htmlBody = this.wrapHtml(
      `<h2>Order Status Update</h2>` +
        `<p>${this.escapeHtml(payload.body)}</p>` +
        `<p><strong>Order ID:</strong> ${this.escapeHtml(orderId)}</p>` +
        `<p><strong>New Status:</strong> ${this.escapeHtml(newStatus)}</p>`,
    );

    return { subject, textBody, htmlBody };
  }

  private renderWelcome(payload: NotificationPayload): {
    subject: string;
    textBody: string;
    htmlBody: string;
  } {
    const subject = `Welcome to ${this.config.appName}!`;
    const textBody = [
      `Hi,`,
      ``,
      `Welcome to ${this.config.appName}!`,
      ``,
      payload.body,
      ``,
      `— The ${this.config.appName} Team`,
    ].join('\n');

    const htmlBody = this.wrapHtml(
      `<h2>Welcome to ${this.escapeHtml(this.config.appName)}!</h2>` +
        `<p>${this.escapeHtml(payload.body)}</p>`,
    );

    return { subject, textBody, htmlBody };
  }

  private renderAccountUpdated(payload: NotificationPayload): {
    subject: string;
    textBody: string;
    htmlBody: string;
  } {
    const subject = `${this.config.appName} — Account Updated`;
    const textBody = [
      `Hi,`,
      ``,
      payload.body,
      ``,
      `If you did not make this change, please contact support immediately.`,
      ``,
      `— The ${this.config.appName} Team`,
    ].join('\n');

    const htmlBody = this.wrapHtml(
      `<h2>Account Updated</h2>` +
        `<p>${this.escapeHtml(payload.body)}</p>` +
        `<p><em>If you did not make this change, please contact support immediately.</em></p>`,
    );

    return { subject, textBody, htmlBody };
  }

  private renderGeneric(payload: NotificationPayload): {
    subject: string;
    textBody: string;
    htmlBody: string;
  } {
    const subject = payload.subject;
    const textBody = [payload.body, ``, `— The ${this.config.appName} Team`].join('\n');
    const htmlBody = this.wrapHtml(`<p>${this.escapeHtml(payload.body)}</p>`);
    return { subject, textBody, htmlBody };
  }

  // ---------------------------------------------------------------------------
  // Recipient validation
  // ---------------------------------------------------------------------------

  private validateRecipient(recipient: string): string | null {
    if (!recipient) {
      return 'Recipient email is required';
    }
    if (!EMAIL_REGEX.test(recipient)) {
      return `Invalid email format: ${recipient}`;
    }
    return null;
  }

  // ---------------------------------------------------------------------------
  // Transport layer
  // ---------------------------------------------------------------------------

  /**
   * Internal email transport. By default this always succeeds (in-memory).
   * In production replace with a real SMTP / API call.
   * Use `setTransport()` in tests to simulate failures.
   */
  private async sendEmail(email: SentEmail): Promise<boolean> {
    if (this.transportFn) {
      return this.transportFn(email);
    }
    // Default: successful in-memory delivery
    return true;
  }

  /**
   * Override the internal transport function. Useful in tests to simulate
   * transient failures, permanent failures, or latency.
   */
  setTransport(fn: (email: SentEmail) => Promise<boolean>): void {
    this.transportFn = fn;
  }

  // ---------------------------------------------------------------------------
  // HTML helpers
  // ---------------------------------------------------------------------------

  private wrapHtml(bodyContent: string): string {
    return [
      '<!DOCTYPE html>',
      '<html><head><meta charset="utf-8"></head>',
      '<body style="font-family:sans-serif;max-width:600px;margin:0 auto;padding:20px">',
      bodyContent,
      `<hr><p style="font-size:12px;color:#888">&mdash; The ${this.escapeHtml(this.config.appName)} Team</p>`,
      '</body></html>',
    ].join('');
  }

  private escapeHtml(text: string): string {
    return text
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  // ---------------------------------------------------------------------------
  // Inspection helpers (testing / debugging)
  // ---------------------------------------------------------------------------

  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  clearSentEmails(): void {
    this.sentEmails = [];
  }

  getConfig(): EmailAdapterConfig {
    return { ...this.config };
  }
}

